const LevelCalculator = {
  getLevelInfo: (earnedXP) => {
    const data = LEVEL_DATA.find((l) => earnedXP >= l.min && earnedXP <= l.max) || LEVEL_DATA[LEVEL_DATA.length - 1];
    const nextLvl = LEVEL_DATA.find((l) => l.lvl === data.lvl + 1);
    let progress = 100;
    let nextXP = data.max;
    if (nextLvl) {
      const range = data.max - data.min;
      const current = earnedXP - data.min;
      progress = range > 0 ? current / range * 100 : 100;
      nextXP = data.max + 1;
    }
    const lvl = data.lvl;
    let buffsArray = [];
    const exclSlots = 3 + Math.floor(lvl / 3);
    if (lvl === 1) {
      buffsArray.push("150 Pontos iniciais", "Origem", "Kit Inicial baseado na Origem");
    }
    buffsArray.push(`+${lvl} de HP em todas as partes`);
    buffsArray.push(`+${exclSlots} Slots de Exclusividade`);
    if (lvl > 1 && lvl % 3 === 0) {
      buffsArray.push("Habilidade de Origem");
    }
    if (lvl >= 10) {
      buffsArray.push("NÍVEL MÁXIMO");
    }
    return {
      level: data.lvl,
      limits: data.limits,
      buffs: buffsArray.join(", "),
      progress: Math.min(100, Math.max(0, progress)),
      // Mantém a barra entre 0% e 100%
      currentXP: earnedXP,
      nextXP
    };
  }
};
