const SystemBookDB = {
  // Inicializa a configuração no Foundry VTT
  init: () => {
    if (!game.settings.settings.has(`${MODULE_ID$D}.srd_books`)) {
      game.settings.register(MODULE_ID$D, "srd_books", {
        scope: "world",
        config: false,
        type: Array,
        default: []
      });
    }
    if (!game.settings.settings.has(`${MODULE_ID$D}.srd_glossary`)) {
      game.settings.register(MODULE_ID$D, "srd_glossary", {
        scope: "world",
        config: false,
        type: Object,
        default: {}
      });
    }
  },
  getBooks: () => {
    return game.settings.get(MODULE_ID$D, "srd_books") || [];
  },
  saveBooks: async (booksArray) => {
    await game.settings.set(MODULE_ID$D, "srd_books", booksArray);
  },
  getGlossary: () => {
    return game.settings.get(MODULE_ID$D, "srd_glossary") || {};
  },
  saveGlossary: async (glossaryObj) => {
    await game.settings.set(MODULE_ID$D, "srd_glossary", glossaryObj);
  },
  // Cria um livro novo estruturado
  createNewBook: async (title = "Novo Livro do Sistema") => {
    const books = SystemBookDB.getBooks();
    const newBook = {
      id: foundry.utils.randomID(),
      type: "book",
      category: "GERAL",
      title,
      summary: "Sinopse do livro de regras...",
      image: "https://placehold.co/400x200/0a0a0c/00ff41?text=LIVRO+DE+REGRAS",
      chapters: [
        {
          id: foundry.utils.randomID(),
          folder: "Introdução",
          // Categoria para o Índice
          title: "Página Inicial",
          content: "# Bem-vindo\nEscreva as regras aqui...",
          customHtml: ""
        }
      ]
    };
    books.push(newBook);
    await SystemBookDB.saveBooks(books);
    return newBook;
  }
};
const BookAutomation = {
  renderMarkdown: (text2, glossary) => {
    if (!text2) return "";
    let html = text2.replace(/\r\n/g, "\n");
    html = html.replace(/\[img:(.+):([^:]+)\]/g, '<img src="$1" style="width: $2; max-width: 100%; border-radius: 4px;" class="live-img" data-url="$1">');
    html = html.replace(/\[color:(.*?)\](.*?)\[\/color\]/g, '<span style="color: $1;">$2</span>');
    html = html.replace(/(?:^>.*(?:\n|$))+/gm, (match) => {
      let lines = match.split("\n").filter((l) => l.trim().length > 0);
      let contentLines = lines.map((l) => l.replace(/^>\s?/, "").trim());
      if (contentLines.length > 0 && contentLines[0].startsWith("## ")) {
        let title = contentLines[0].replace(/^##\s*/, "");
        let body = contentLines.slice(1).join("<br>");
        return `
<div class="dh-callout"><div class="callout-title">${title}</div><div class="callout-body">${body}</div></div>
`;
      } else {
        return `
<blockquote>${contentLines.join("<br>")}</blockquote>
`;
      }
    });
    html = html.replace(/^# (.*?)$/gm, '<h1 class="chapter-title">$1</h1>');
    html = html.replace(/^## (.*?)$/gm, '<h2 class="section-title">$1</h2>');
    html = html.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");
    html = html.replace(/\*(.*?)\*/g, "<em>$1</em>");
    html = html.replace(/_(.*?)_/g, "<em>$1</em>");
    html = html.replace(/^-\s+(.*?)$/gm, '<li class="md-list-item">$1</li>');
    const blocks = html.split(/\n\s*\n/);
    html = blocks.map((block) => {
      const isHtmlBlock = /^<(h[1-6]|div|blockquote|ul|ol|li|img|span)/i.test(block.trim());
      if (isHtmlBlock || block.trim() === "") return block;
      return `<p>${block.replace(/\n/g, "<br>")}</p>`;
    }).join("\n");
    html = html.replace(/(<li class="md-list-item">.*?<\/li>\s*)+/g, (match) => `<ul class="md-list">${match}</ul>`);
    if (glossary && Object.keys(glossary).length > 0) {
      const terms = Object.entries(glossary).filter(([_, data]) => data.word).sort((a, b) => b[1].word.length - a[1].word.length);
      let parts = html.split(/(<[^>]*>)/g);
      for (let i = 0; i < parts.length; i++) {
        if (i % 2 === 0) {
          for (const [key, data] of terms) {
            const escapedWord = data.word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
            const regex = new RegExp(`(^|[^a-zA-Z0-9À-ÿ])(${escapedWord})([^a-zA-Z0-9À-ÿ]|$)`, "gi");
            parts[i] = parts[i].replace(regex, `$1<span class="rule-keyword" data-key="${key}">$2</span>$3`);
          }
        }
      }
      html = parts.join("");
    }
    return html;
  }
};
